mapper.select:
/* com.erns.coching.rnd.mapper.AiLabResDAO.getList */

SELECT

FROM T_AI_LAB_RES AA





		ORDER BY AA.AI_LAB_MST_SEQ DESC



	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.rnd.mapper.AiLabResDAO.load */

SELECT

FROM T_AI_LAB_RES AA

	AND AA.AI_LAB_MST_SEQ = #{resSeq	, jdbcType=INTEGER}

mapper.update:
/* com.erns.coching.rnd.mapper.AiLabResDAO.update */

UPDATE T_AI_LAB_RES SET
		LAB_MST_SEQ 	= #{labMstSeq	, jdbcType=INTEGER}
	, AI_LAB_PARAM   	= 
		CAST(#{aiLabParam} AS jsonb)
		NULL

	, AI_LAB_RES     	= 
		CAST(#{aiLabRes} AS jsonb)
		NULL


	AND AI_LAB_MST_SEQ 	= #{aiLabMstSeq	, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.rnd.mapper.AiLabResDAO.delete */

DELETE FROM T_AI_LAB_RES

	AND AI_LAB_MST_SEQ = #{resSeq, jdbcType=INTEGER}

/* com.erns.coching.rnd.mapper.AiLabResDAO.deleteByLabMstSeq */

DELETE FROM T_AI_LAB_RES

  AND LAB_MST_SEQ = #{labMstSeq, jdbcType=INTEGER}
